-- =============================================================
-- Data Source
-- Database  : ods_bankcredit (MySQL)
-- =============================================================

DROP DATABASE IF EXISTS `ods_bankcredit`;
CREATE DATABASE `ods_bankcredit` DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `ods_bankcredit`;

-- -------------------------------------------------------------
-- Table: ods_loan_transactions
-- -------------------------------------------------------------
DROP TABLE IF EXISTS `ods_loan_transactions`;
CREATE TABLE `ods_loan_transactions` (
  `application_id` INT NOT NULL PRIMARY KEY,
  `application_date` DATE,
  `requested_amount` DECIMAL(18,2),
  `tenor_months` INT,
  `purpose` VARCHAR(100),
  `app_status` VARCHAR(30),
  `customer_id` INT,
  `national_id` VARCHAR(30),
  `customer_name` VARCHAR(100),
  `date_of_birth` DATE,
  `occupation` VARCHAR(50),
  `monthly_income` DECIMAL(18,2),
  `risk_segment` INT,
  `email` VARCHAR(100),
  `phone` VARCHAR(20),
  `credit_score` INT,
  `credit_grade` VARCHAR(10),
  `rating_date` DATE,
  `bureau_source` VARCHAR(30),
  `product_id` INT,
  `product_code` VARCHAR(20),
  `product_name` VARCHAR(100),
  `product_type` VARCHAR(50),
  `product_interest_rate` DECIMAL(6,2),
  `min_amount` DECIMAL(18,2),
  `max_amount` DECIMAL(18,2),
  `max_tenor_months` INT,
  `branch_id` INT,
  `branch_code` VARCHAR(20),
  `branch_name` VARCHAR(100),
  `city` VARCHAR(50),
  `region` VARCHAR(30),
  `branch_opened_date` DATE,
  `assessment_id` INT,
  `dti_ratio` DECIMAL(8,2),
  `pd_score` DECIMAL(8,4),
  `recommendation` VARCHAR(30),
  `assessor_notes` VARCHAR(255),
  `assessed_on` DATE,
  `pledge_id` INT,
  `collateral_type_id` INT,
  `collateral_type_name` VARCHAR(100),
  `ltv_ratio` DECIMAL(8,2),
  `appraised_value` DECIMAL(18,2),
  `document_ref` VARCHAR(50),
  `pledge_date` DATE,
  `approval_id` INT,
  `approver_id` INT,
  `approver_name` VARCHAR(100),
  `approver_role` VARCHAR(50),
  `approved_amount` DECIMAL(18,2),
  `final_rate` DECIMAL(6,2),
  `approval_date` DATE,
  `decision` VARCHAR(20),
  `disbursement_id` INT,
  `disbursed_amount` DECIMAL(18,2),
  `disbursed_on` DATE,
  `account_no` VARCHAR(30),
  `channel` VARCHAR(30)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Data for ods_loan_transactions

-- -------------------------------------------------------------
-- Table: ods_loan_payments
-- -------------------------------------------------------------
DROP TABLE IF EXISTS `ods_loan_payments`;
CREATE TABLE `ods_loan_payments` (
  `payment_id` INT NOT NULL PRIMARY KEY,
  `disbursement_id` INT,
  `installment_no` INT,
  `principal` DECIMAL(18,2),
  `interest` DECIMAL(18,2),
  `due_date` DATE,
  `paid_date` DATE,
  `payment_status` VARCHAR(20),
  `approval_id` INT,
  `disbursed_amount` DECIMAL(18,2),
  `disbursed_on` DATE,
  `account_no` VARCHAR(30),
  `channel` VARCHAR(30),
  `application_id` INT,
  `approved_amount` DECIMAL(18,2),
  `final_rate` DECIMAL(6,2),
  `decision` VARCHAR(20),
  `customer_id` INT,
  `customer_name` VARCHAR(100),
  `product_id` INT,
  `product_code` VARCHAR(20),
  `branch_id` INT,
  `branch_code` VARCHAR(20)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Data for ods_loan_payments
